// ─── Three.js CPU Die Hero ───────────────────────────────────
const GamingPCHero = () => {
  const mountRef = useRef(null);
  const rotRef = useRef(0);

  useEffect(() => {
    if (!mountRef.current) return;
    const w = mountRef.current.clientWidth;
    const h = mountRef.current.clientHeight;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(30, w / h, 0.1, 100);
    // Camera positioned to look through the glass side panel
    camera.position.set(4, 1.2, 2.5);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.2;
    mountRef.current.appendChild(renderer.domElement);

    const pc = new THREE.Group();
    scene.add(pc);

    // === Materials ===
    const caseMat = new THREE.MeshPhysicalMaterial({ color: 0xe8e8ec, metalness: 0.15, roughness: 0.35, clearcoat: 0.6, clearcoatRoughness: 0.15 });
    const glassMat = new THREE.MeshPhysicalMaterial({ color: 0xffffff, metalness: 0.0, roughness: 0.0, transparent: true, opacity: 0.08, transmission: 0.92, thickness: 0.015, clearcoat: 1, clearcoatRoughness: 0.0, side: THREE.DoubleSide, envMapIntensity: 0.5 });
    const darkMat = new THREE.MeshPhysicalMaterial({ color: 0x1a1a20, metalness: 0.6, roughness: 0.35 });
    const pcbMat = new THREE.MeshPhysicalMaterial({ color: 0x0d1f15, metalness: 0.15, roughness: 0.7 });
    const pinkMat = new THREE.MeshStandardMaterial({ color: 0xee44aa, emissive: 0xee44aa, emissiveIntensity: 1.5, transparent: true, opacity: 0.85 });
    const pinkGlow = new THREE.MeshBasicMaterial({ color: 0xff66cc, transparent: true, opacity: 0.15 });
    const goldMat = new THREE.MeshPhysicalMaterial({ color: 0xd4a843, metalness: 0.85, roughness: 0.15 });

    // === Dimensions (realistic mid-tower proportions) ===
    const W = 0.9;   // width (left-right, glass side)
    const H = 1.9;   // height
    const D = 1.7;   // depth (front-back)

    // === Case Frame (5 panels, glass on right/viewer side) ===
    const t = 0.03;  // panel thickness

    // Back panel
    pc.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(W, H, t), caseMat), { position: new THREE.Vector3(0, 0, -D / 2) }));
    // Top panel
    pc.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(W, t, D), caseMat), { position: new THREE.Vector3(0, H / 2, 0) }));
    // Bottom panel
    pc.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(W, t, D), caseMat), { position: new THREE.Vector3(0, -H / 2, 0) }));
    // Left panel (solid, far side)
    pc.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(t, H, D), caseMat), { position: new THREE.Vector3(-W / 2, 0, 0) }));
    // Right panel (GLASS, facing camera)
    pc.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(t, H * 0.95, D * 0.95), glassMat), { position: new THREE.Vector3(W / 2, 0, 0) }));

    // Front panel — mesh-style (vertical slats with gaps for airflow/fans)
    for (let i = 0; i < 12; i++) {
      const slat = new THREE.Mesh(new THREE.BoxGeometry(W * 0.85, 0.015, t), caseMat);
      slat.position.set(0, -H / 2 + 0.15 + i * (H * 0.78 / 12), D / 2);
      pc.add(slat);
    }
    // Front panel side rails
    pc.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(0.04, H, t), caseMat), { position: new THREE.Vector3(-W / 2 + 0.05, 0, D / 2) }));
    pc.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(0.04, H, t), caseMat), { position: new THREE.Vector3(W / 2 - 0.05, 0, D / 2) }));

    // === Case feet ===
    const footGeo = new THREE.BoxGeometry(0.08, 0.06, 0.15);
    [[-1, -1], [1, -1], [-1, 1], [1, 1]].forEach(([x, z]) => {
      pc.add(Object.assign(new THREE.Mesh(footGeo, darkMat), { position: new THREE.Vector3(x * (W / 2 - 0.08), -H / 2 - 0.03, z * (D / 2 - 0.12)) }));
    });

    // === Motherboard (flat against back panel) ===
    const mobo = new THREE.Mesh(new THREE.BoxGeometry(W * 0.8, H * 0.6, 0.02), pcbMat);
    mobo.position.set(0, 0.15, -D / 2 + 0.06);
    pc.add(mobo);

    // Mobo circuit traces (subtle lines)
    for (let i = 0; i < 5; i++) {
      const trace = new THREE.Mesh(new THREE.BoxGeometry(W * 0.5, 0.003, 0.001), new THREE.MeshBasicMaterial({ color: 0x1a3525 }));
      trace.position.set(-0.02, -0.15 + i * 0.18, -D / 2 + 0.075);
      pc.add(trace);
    }

    // === CPU (square die on mobo) ===
    const cpuDie = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.15, 0.015), new THREE.MeshPhysicalMaterial({ color: 0x888888, metalness: 0.8, roughness: 0.1 }));
    cpuDie.position.set(0, 0.35, -D / 2 + 0.08);
    pc.add(cpuDie);

    // === AIO Cooler Pump Head (cylinder on CPU) ===
    const pumpHead = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.08, 0.04, 24), darkMat);
    pumpHead.rotation.x = Math.PI / 2;
    pumpHead.position.set(0, 0.35, -D / 2 + 0.11);
    pc.add(pumpHead);
    // Pump RGB ring
    const pumpRing = new THREE.Mesh(new THREE.TorusGeometry(0.075, 0.008, 8, 32), pinkMat);
    pumpRing.position.set(0, 0.35, -D / 2 + 0.135);
    pc.add(pumpRing);

    // AIO tubes (two curves going up to top-mounted radiator)
    [[-0.04, 0.04]].forEach(([x1, x2]) => {
      [x1, x2].forEach(x => {
        const tube = new THREE.Mesh(new THREE.CylinderGeometry(0.012, 0.012, 0.55, 8), darkMat);
        tube.position.set(x, 0.65, -D / 2 + 0.12);
        pc.add(tube);
      });
    });

    // Top-mounted AIO radiator
    const radiator = new THREE.Mesh(new THREE.BoxGeometry(W * 0.7, 0.06, D * 0.2), darkMat);
    radiator.position.set(0, H / 2 - 0.06, -D / 2 + 0.25);
    pc.add(radiator);

    // === GPU (horizontal, below center) ===
    const gpuBody = new THREE.Mesh(new THREE.BoxGeometry(W * 0.7, 0.06, D * 0.35), darkMat);
    gpuBody.position.set(0, -0.15, -D / 2 + 0.35);
    pc.add(gpuBody);
    // GPU backplate (slight overhang)
    const gpuPlate = new THREE.Mesh(new THREE.BoxGeometry(W * 0.72, 0.01, D * 0.35), new THREE.MeshPhysicalMaterial({ color: 0x333338, metalness: 0.5, roughness: 0.3 }));
    gpuPlate.position.set(0, -0.11, -D / 2 + 0.35);
    pc.add(gpuPlate);
    // GPU RGB accent
    const gpuRgb = new THREE.Mesh(new THREE.BoxGeometry(W * 0.6, 0.008, 0.008), pinkMat);
    gpuRgb.position.set(0, -0.125, -D / 2 + 0.17);
    pc.add(gpuRgb);
    // GPU fans (2x)
    [-0.12, 0.12].forEach(x => {
      const gpuFanRing = new THREE.Mesh(new THREE.TorusGeometry(0.1, 0.008, 8, 24), darkMat);
      gpuFanRing.rotation.x = Math.PI / 2;
      gpuFanRing.position.set(x, -0.19, -D / 2 + 0.35);
      pc.add(gpuFanRing);
    });

    // === RAM (4 sticks, vertical, right of CPU) ===
    for (let i = 0; i < 4; i++) {
      const ram = new THREE.Mesh(new THREE.BoxGeometry(0.012, 0.32, 0.04), darkMat);
      ram.position.set(0.22 + i * 0.03, 0.38, -D / 2 + 0.075);
      pc.add(ram);
      // RAM RGB top strips
      const ramTop = new THREE.Mesh(new THREE.BoxGeometry(0.012, 0.04, 0.04), pinkMat);
      ramTop.position.set(0.22 + i * 0.03, 0.56, -D / 2 + 0.075);
      pc.add(ramTop);
    }

    // === PSU Shroud (bottom of case) ===
    const psuShroud = new THREE.Mesh(new THREE.BoxGeometry(W * 0.95, 0.3, D * 0.95), caseMat);
    psuShroud.position.set(0, -H / 2 + 0.17, 0);
    pc.add(psuShroud);

    // === Front Fans (3x 120mm, behind mesh front panel) ===
    const fanBlades = [];
    [0.55, 0, -0.55].forEach(y => {
      // Fan housing ring
      const ring = new THREE.Mesh(new THREE.TorusGeometry(0.2, 0.015, 12, 32), caseMat);
      ring.position.set(0, y, D / 2 - 0.06);
      pc.add(ring);
      // Glow disc behind blades
      const gDisc = new THREE.Mesh(new THREE.CircleGeometry(0.18, 32), pinkGlow);
      gDisc.position.set(0, y, D / 2 - 0.07);
      pc.add(gDisc);
      // 7 blades per fan
      for (let b = 0; b < 7; b++) {
        const blade = new THREE.Mesh(new THREE.BoxGeometry(0.14, 0.018, 0.006), pinkMat);
        blade.position.set(0, y, D / 2 - 0.06);
        blade.rotation.z = (b / 7) * Math.PI * 2;
        pc.add(blade);
        fanBlades.push(blade);
      }
      // Point light
      const fl = new THREE.PointLight(0xff66cc, 0.6, 1.8);
      fl.position.set(0.15, y, D / 2 + 0.08);
      pc.add(fl);
    });

    // === Internal Glow ===
    const interiorGlow = new THREE.PointLight(0xff55bb, 0.25, 2.5);
    interiorGlow.position.set(0, 0, 0);
    pc.add(interiorGlow);

    // === Scene Lighting ===
    scene.add(new THREE.AmbientLight(0xffffff, 1.3));
    const kl = new THREE.DirectionalLight(0xffffff, 1.8);
    kl.position.set(5, 6, 4);
    scene.add(kl);
    const fl2 = new THREE.DirectionalLight(0xeef2ff, 0.6);
    fl2.position.set(-4, 3, -2);
    scene.add(fl2);
    const rl = new THREE.DirectionalLight(0xfff8f0, 0.4);
    rl.position.set(0, -1, 5);
    scene.add(rl);

    // Subtle ground shadow
    const gnd = new THREE.Mesh(new THREE.CircleGeometry(2.5, 32), new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.04 }));
    gnd.rotation.x = -Math.PI / 2;
    gnd.position.y = -H / 2 - 0.04;
    scene.add(gnd);

    // Scroll rotation
    const onScroll = () => { rotRef.current = window.scrollY * 0.0008; };
    window.addEventListener('scroll', onScroll, { passive: true });

    let raf;
    const animate = () => {
      raf = requestAnimationFrame(animate);
      pc.rotation.y = -0.35 + rotRef.current + Math.sin(Date.now() * 0.00025) * 0.06;
      pc.rotation.x = 0.05;
      fanBlades.forEach(b => { b.rotation.z += 0.035; });
      renderer.render(scene, camera);
    };
    animate();

    const onResize = () => {
      const nw = mountRef.current?.clientWidth || w;
      const nh = mountRef.current?.clientHeight || h;
      camera.aspect = nw / nh;
      camera.updateProjectionMatrix();
      renderer.setSize(nw, nh);
    };
    window.addEventListener('resize', onResize);

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('scroll', onScroll);
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      if (mountRef.current?.contains(renderer.domElement)) {
        mountRef.current.removeChild(renderer.domElement);
      }
    };
  }, []);

  return <div ref={mountRef} className="hero-canvas" />;
};


